# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    try:
        message = event['message']
        topic_arn = event['topic_arn']
        notification_type = event['notification_type']

        if notification_type == 'INFO':
            sns_client.publish(TopicArn=topic_arn, Message=message, Subject='Info Notification')
        elif notification_type == 'WARNING':
            sns_client.publish(TopicArn=topic_arn, Message=message, Subject='Warning Notification')
        elif notification_type == 'ERROR':
            sns_client.publish(TopicArn=topic_arn, Message=message, Subject='Error Notification')
        else:
            raise ValueError('Invalid notification type.')

        return {
            'statusCode': 200,
            'body': 'Notification published successfully.'
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': str(e)
        }